module multi_pipe_4bit #(
    parameter size = 4
)(
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    output reg [(2*size)-1:0] mul_out
);

    wire [2*size-1:0] extended_a;
    wire [2*size-1:0] extended_b;

    genvar i;
        for (i = 0; i < size; i = i + 1) begin
            assign extended_a[i*2+:size] = {size{i[0]}};
            assign extended_b[i*2+:size] = {size{mul_b[i]}};
        end

    reg [2*size-1:0] stage1_product;
    reg [2*size-1:0] stage2_product;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            stage1_product <= 'b0;
            stage2_product <= 'b0;
        end else begin
            stage1_product <= extended_a * extended_b;
            stage2_product <= stage1_product;
        end
    end

    always @(*) begin
        mul_out = stage2_product;
    end

endmodule
